export type GoogleSansCodeWeight = "300" | "400" | "500" | "600" | "700" | "800";
export type GoogleSansCodeStyle = "italic" | "normal";
export type GoogleSansCodeSubset =
  | "adlam"
  | "canadian-aboriginal"
  | "cherokee"
  | "latin"
  | "latin-ext"
  | "math"
  | "old-permic"
  | "symbols"
  | "symbols2"
  | "syriac"
  | "vietnamese";
export type GoogleSansCodeOptions = GoogleFontOptions<
  GoogleSansCodeWeight,
  GoogleSansCodeStyle,
  GoogleSansCodeSubset
>;

/**
 * Google Sans Code — Google font. Pass `weights`/`styles` to register a subset of
 * faces (omit for all) and `subset` to choose the character set (default "latin").
 */
export default class GoogleSansCode extends GoogleFont<
  GoogleSansCodeWeight,
  GoogleSansCodeStyle,
  GoogleSansCodeSubset
> {
  constructor(options?: GoogleSansCodeOptions) {
    super(FAMILY, FACES, options);
  }
}
